def fib(n: int) -> int:
    # Dictionary to store computed Fibonacci numbers
    memo = {0: 0, 1: 1}

    def helper(k: int) -> int:
        # Check if the value is already in the memo
        if k in memo:
            return memo[k]

        # Otherwise, compute it recursively and store it
        memo[k] = helper(k - 1) + helper(k - 2)
        return memo[k]

    return helper(n)

# Examples
